import React, { useState, useEffect } from 'react';

const DoctorDashboard = ({ user, onLogout }) => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [queueData, setQueueData] = useState([]);
  const [stats, setStats] = useState({
    patientsInQueue: 0,
    todaysAppointments: 0
  });
  const [loading, setLoading] = useState(true);
  const [patients, setPatients] = useState([]);
  const [selectedPatient, setSelectedPatient] = useState(null);
  const [showPrescriptionModal, setShowPrescriptionModal] = useState(false);
  const [showLabTestModal, setShowLabTestModal] = useState(false);
  const [prescriptions, setPrescriptions] = useState([]);
  const [labTests, setLabTests] = useState([]);
  const [selectedPatientHistory, setSelectedPatientHistory] = useState(null);
  const [patientTriageHistory, setPatientTriageHistory] = useState([]);
  
  // Prescription form state
  const [prescriptionForm, setPrescriptionForm] = useState({
    medication_name: '',
    dosage: '',
    frequency: '',
    duration: '',
    instructions: ''
  });
  
  // Lab test form state
  const [labTestForm, setLabTestForm] = useState({
    test_type: 'hematology',
    test_name: '',
    notes: ''
  });
  
  const commonLabTests = {
    hematology: ['Complete Blood Count (CBC)', 'Blood Typing', 'ESR'],
    chemistry: ['Comprehensive Metabolic Panel', 'Liver Function Tests', 'Kidney Function Tests', 'Lipid Profile', 'Blood Glucose', 'HbA1c'],
    microbiology: ['Blood Culture', 'Urine Culture', 'Wound Culture', 'Stool Culture'],
    immunology: ['HIV Test', 'Hepatitis B Surface Antigen', 'Hepatitis C Antibody', 'VDRL/RPR'],
    urinalysis: ['Urine Analysis', 'Urine Pregnancy Test'],
    parasitology: ['Stool Ova & Parasites', 'Blood Parasite Smear']
  };

  useEffect(() => {
    fetchDashboardData();
    if (activeTab === 'pharmacy') {
      fetchPrescriptions();
    } else if (activeTab === 'laboratory') {
      fetchLabTests();
    }
  }, [activeTab]);

  const fetchPatientTriageHistory = async (patientId) => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`http://localhost:5000/api/triage/patient/${patientId}`, {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      
      if (response.ok) {
        const data = await response.json();
        setPatientTriageHistory(data);
      }
    } catch (error) {
      console.error('Error fetching patient triage history:', error);
    }
  };

  const fetchDashboardData = async () => {
    try {
      const token = localStorage.getItem('token');
      
      // Fetch queue data
      const queueResponse = await fetch('http://localhost:5000/api/queue', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      
      if (queueResponse.ok) {
        const queueData = await queueResponse.json();
        setQueueData(queueData.filter(q => q.status === 'waiting').slice(0, 5));
        setStats(prev => ({
          ...prev,
          patientsInQueue: queueData.filter(q => q.status === 'waiting').length
        }));
      }

      // Fetch patients
      const patientsResponse = await fetch('http://localhost:5000/api/patients', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      
      if (patientsResponse.ok) {
        const patientsData = await patientsResponse.json();
        setPatients(patientsData);
      }

      // Fetch appointments (mock for now)
      setStats(prev => ({
        ...prev,
        todaysAppointments: 15
      }));

      setLoading(false);
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
      setLoading(false);
    }
  };
  
  const fetchPrescriptions = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch('http://localhost:5000/api/prescriptions', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      
      if (response.ok) {
        const data = await response.json();
        setPrescriptions(data);
      }
    } catch (error) {
      console.error('Error fetching prescriptions:', error);
    }
  };
  
  const fetchLabTests = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch('http://localhost:5000/api/lab-tests', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      
      if (response.ok) {
        const data = await response.json();
        setLabTests(data);
      }
    } catch (error) {
      console.error('Error fetching lab tests:', error);
    }
  };
  
  const handleCreatePrescription = async (e) => {
    e.preventDefault();
    
    if (!selectedPatient) {
      alert('Please select a patient first');
      return;
    }
    
    try {
      const token = localStorage.getItem('token');
      const response = await fetch('http://localhost:5000/api/prescriptions', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({
          patient_id: selectedPatient.id,
          ...prescriptionForm
        })
      });
      
      if (response.ok) {
        alert('Prescription created successfully!');
        setShowPrescriptionModal(false);
        setPrescriptionForm({
          medication_name: '',
          dosage: '',
          frequency: '',
          duration: '',
          instructions: ''
        });
        setSelectedPatient(null);
        fetchPrescriptions();
      } else {
        const error = await response.json();
        alert('Error: ' + error.message);
      }
    } catch (error) {
      console.error('Error creating prescription:', error);
      alert('Failed to create prescription');
    }
  };
  
  const handleCreateLabTest = async (e) => {
    e.preventDefault();
    
    if (!selectedPatient) {
      alert('Please select a patient first');
      return;
    }
    
    try {
      const token = localStorage.getItem('token');
      const response = await fetch('http://localhost:5000/api/lab-tests', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({
          patient_id: selectedPatient.id,
          ...labTestForm
        })
      });
      
      if (response.ok) {
        alert('Lab test ordered successfully!');
        setShowLabTestModal(false);
        setLabTestForm({
          test_type: 'hematology',
          test_name: '',
          notes: ''
        });
        setSelectedPatient(null);
        fetchLabTests();
      } else {
        const error = await response.json();
        alert('Error: ' + error.message);
      }
    } catch (error) {
      console.error('Error creating lab test:', error);
      alert('Failed to order lab test');
    }
  };

  const handleCallNext = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch('http://localhost:5000/api/queue/call-next', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({
          doctor_id: user.id,
          room_number: 'Room 101'
        })
      });

      if (response.ok) {
        fetchDashboardData(); // Refresh data
        alert('Patient called to consultation');
      }
    } catch (error) {
      console.error('Error calling next patient:', error);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex">
      {/* Sidebar */}
      <div className="w-64 bg-slate-800 text-white min-h-screen">
        <div className="p-6">
          <div className="flex items-center space-x-2 mb-2">
            <div className="w-10 h-10 bg-gradient-to-br from-green-400 to-blue-500 rounded-lg flex items-center justify-center">
              <span className="text-white text-xl">🏥</span>
            </div>
            <div>
              <h1 className="text-xl font-bold">Patient</h1>
              <h2 className="text-lg font-semibold">Management</h2>
            </div>
          </div>
        </div>

        <nav className="mt-8">
          <button
            onClick={() => setActiveTab('dashboard')}
            className={`w-full flex items-center px-6 py-3 text-left transition-colors ${
              activeTab === 'dashboard'
                ? 'bg-blue-600 border-l-4 border-blue-400'
                : 'hover:bg-slate-700'
            }`}
          >
            <span className="mr-3">📊</span>
            Dashboard
          </button>
          
          <button
            onClick={() => setActiveTab('queue')}
            className={`w-full flex items-center px-6 py-3 text-left transition-colors ${
              activeTab === 'queue'
                ? 'bg-blue-600 border-l-4 border-blue-400'
                : 'hover:bg-slate-700'
            }`}
          >
            <span className="mr-3">📋</span>
            Appointment/Queue
          </button>
          
          <button
            onClick={() => setActiveTab('laboratory')}
            className={`w-full flex items-center px-6 py-3 text-left transition-colors ${
              activeTab === 'laboratory'
                ? 'bg-blue-600 border-l-4 border-blue-400'
                : 'hover:bg-slate-700'
            }`}
          >
            <span className="mr-3">🔬</span>
            Laboratory
          </button>
          
          <button
            onClick={() => setActiveTab('pharmacy')}
            className={`w-full flex items-center px-6 py-3 text-left transition-colors ${
              activeTab === 'pharmacy'
                ? 'bg-blue-600 border-l-4 border-blue-400'
                : 'hover:bg-slate-700'
            }`}
          >
            <span className="mr-3">💊</span>
            Pharmacy
          </button>
          
          <button
            onClick={() => setActiveTab('patientHistory')}
            className={`w-full flex items-center px-6 py-3 text-left transition-colors ${
              activeTab === 'patientHistory'
                ? 'bg-blue-600 border-l-4 border-blue-400'
                : 'hover:bg-slate-700'
            }`}
          >
            <span className="mr-3">📋</span>
            Patient History
          </button>
          
          <button
            onClick={() => setActiveTab('portfolio')}
            className={`w-full flex items-center px-6 py-3 text-left transition-colors ${
              activeTab === 'portfolio'
                ? 'bg-blue-600 border-l-4 border-blue-400'
                : 'hover:bg-slate-700'
            }`}
          >
            <span className="mr-3">👤</span>
            Portfolio
          </button>
        </nav>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col">
        {/* Header */}
        <header className="bg-white shadow-sm">
          <div className="px-8 py-4 flex justify-between items-center">
            <div>
              <h2 className="text-2xl font-bold text-gray-900">Doctor Dashboard</h2>
              <p className="text-sm text-gray-500">Last updated: {new Date().toLocaleTimeString()}</p>
            </div>

            <div className="flex items-center space-x-4">
              <div className="text-right">
                <p className="text-sm font-medium text-gray-900">Dr. {user?.firstName} {user?.lastName}</p>
                <p className="text-xs text-gray-500">General Physician</p>
              </div>
              <div className="w-12 h-12 bg-gradient-to-br from-blue-400 to-blue-600 rounded-full flex items-center justify-center text-white font-bold text-lg">
                {user?.firstName?.charAt(0)}{user?.lastName?.charAt(0)}
              </div>
              <button
                onClick={onLogout}
                className="px-4 py-2 bg-red-500 text-white rounded-lg hover:bg-red-600 transition-colors"
              >
                Logout
              </button>
            </div>
          </div>
        </header>

        {/* Content Area */}
        <main className="flex-1 p-8 overflow-auto">
          {activeTab === 'dashboard' && (
            <div>
              {/* Welcome Banner */}
              <div className="bg-gradient-to-r from-blue-400 to-green-500 rounded-xl shadow-lg p-8 mb-8 text-white">
                <div className="flex items-center justify-between">
                  <div>
                    <h1 className="text-3xl font-bold mb-2">Welcome, Dr. {user?.firstName}!</h1>
                    <p className="text-lg text-white opacity-90">Have a nice time and try to care your patients kindly!!!</p>
                  </div>
                  <div className="w-20 h-20 bg-white bg-opacity-20 rounded-full flex items-center justify-center">
                    <span className="text-5xl">👨‍⚕️</span>
                  </div>
                </div>
              </div>

              {/* Stats Cards */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
                <div className="bg-white rounded-xl shadow-lg p-6">
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="text-gray-600 mb-1">Patients in Queue</p>
                      <p className="text-4xl font-bold text-gray-900">{stats.patientsInQueue}</p>
                    </div>
                    <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center">
                      <span className="text-3xl">👥</span>
                    </div>
                  </div>
                </div>

                <div className="bg-white rounded-xl shadow-lg p-6">
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="text-gray-600 mb-1">Today's Appointments</p>
                      <p className="text-4xl font-bold text-gray-900">{stats.todaysAppointments}</p>
                    </div>
                    <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center">
                      <span className="text-3xl">✅</span>
                    </div>
                  </div>
                </div>
              </div>

              {/* Current Patient Queue */}
              <div className="bg-white rounded-xl shadow-lg p-6">
                <div className="flex items-center justify-between mb-6">
                  <h3 className="text-xl font-bold text-gray-900">Current Patient Queue</h3>
                  <button
                    onClick={handleCallNext}
                    className="px-6 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition-colors font-semibold"
                  >
                    Call Next Patient
                  </button>
                </div>

                {loading ? (
                  <div className="text-center py-8">
                    <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500 mx-auto"></div>
                    <p className="text-gray-600 mt-4">Loading queue...</p>
                  </div>
                ) : queueData.length === 0 ? (
                  <div className="text-center py-12">
                    <span className="text-6xl mb-4 block">📋</span>
                    <p className="text-gray-600 text-lg">No patients in queue</p>
                  </div>
                ) : (
                  <div className="space-y-3">
                    {queueData.map((patient, index) => (
                      <div
                        key={patient.id}
                        className={`flex items-center justify-between p-4 rounded-lg border-l-4 ${
                          index === 0
                            ? 'bg-blue-50 border-blue-500'
                            : 'bg-gray-50 border-gray-300'
                        }`}
                      >
                        <div className="flex items-center space-x-4">
                          <div className={`w-12 h-12 rounded-full flex items-center justify-center text-white font-bold ${
                            index === 0 ? 'bg-blue-500' : 'bg-gray-400'
                          }`}>
                            {patient.queue_number}
                          </div>
                          <div>
                            <p className="font-semibold text-gray-900">
                              {patient.patient_id}
                            </p>
                            <p className="text-sm text-gray-600">
                              {patient.patient_first_name} {patient.patient_last_name}
                            </p>
                          </div>
                        </div>
                        {index === 0 && (
                          <span className="px-4 py-2 bg-blue-500 text-white rounded-full text-sm font-semibold">
                            Next
                          </span>
                        )}
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          )}

          {activeTab === 'queue' && (
            <div className="bg-white rounded-xl shadow-lg p-8">
              <h3 className="text-2xl font-bold text-gray-900 mb-6">Appointment & Queue Management</h3>
              <p className="text-gray-600">View and manage your appointments and patient queue here.</p>
            </div>
          )}

          {activeTab === 'laboratory' && (
            <div>
              <div className="bg-white rounded-xl shadow-lg p-6 mb-6">
                <div className="flex justify-between items-center mb-6">
                  <h3 className="text-2xl font-bold text-gray-900">Laboratory Orders</h3>
                  <button
                    onClick={() => setShowLabTestModal(true)}
                    className="px-6 py-3 bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition-colors font-semibold"
                  >
                    + Order Lab Test
                  </button>
                </div>
                
                <div className="overflow-x-auto">
                  <table className="min-w-full divide-y divide-gray-200">
                    <thead className="bg-gray-50">
                      <tr>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Patient</th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Test Type</th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Test Name</th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Status</th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Requested</th>
                      </tr>
                    </thead>
                    <tbody className="bg-white divide-y divide-gray-200">
                      {labTests.length === 0 ? (
                        <tr>
                          <td colSpan="5" className="px-6 py-8 text-center text-gray-500">
                            No lab tests ordered yet
                          </td>
                        </tr>
                      ) : (
                        labTests.map((test) => (
                          <tr key={test.id}>
                            <td className="px-6 py-4 whitespace-nowrap">
                              <div className="text-sm font-medium text-gray-900">
                                {test.patient_first_name} {test.patient_last_name}
                              </div>
                              <div className="text-sm text-gray-500">{test.patient_id}</div>
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap">
                              <span className="px-3 py-1 text-xs font-semibold rounded-full bg-blue-100 text-blue-800">
                                {test.test_type}
                              </span>
                            </td>
                            <td className="px-6 py-4">
                              <div className="text-sm text-gray-900">{test.test_name}</div>
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap">
                              <span className={`px-3 py-1 text-xs font-semibold rounded-full ${
                                test.status === 'completed' ? 'bg-green-100 text-green-800' :
                                test.status === 'in_progress' ? 'bg-blue-100 text-blue-800' :
                                'bg-yellow-100 text-yellow-800'
                              }`}>
                                {test.status}
                              </span>
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                              {new Date(test.requested_at).toLocaleDateString()}
                            </td>
                          </tr>
                        ))
                      )}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'pharmacy' && (
            <div>
              <div className="bg-white rounded-xl shadow-lg p-6 mb-6">
                <div className="flex justify-between items-center mb-6">
                  <h3 className="text-2xl font-bold text-gray-900">Prescriptions</h3>
                  <button
                    onClick={() => setShowPrescriptionModal(true)}
                    className="px-6 py-3 bg-green-500 text-white rounded-lg hover:bg-green-600 transition-colors font-semibold"
                  >
                    + Create Prescription
                  </button>
                </div>
                
                <div className="overflow-x-auto">
                  <table className="min-w-full divide-y divide-gray-200">
                    <thead className="bg-gray-50">
                      <tr>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Patient</th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Medication</th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Dosage</th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Frequency</th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Status</th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Issued</th>
                      </tr>
                    </thead>
                    <tbody className="bg-white divide-y divide-gray-200">
                      {prescriptions.length === 0 ? (
                        <tr>
                          <td colSpan="6" className="px-6 py-8 text-center text-gray-500">
                            No prescriptions created yet
                          </td>
                        </tr>
                      ) : (
                        prescriptions.map((prescription) => (
                          <tr key={prescription.id}>
                            <td className="px-6 py-4 whitespace-nowrap">
                              <div className="text-sm font-medium text-gray-900">
                                {prescription.patient_first_name} {prescription.patient_last_name}
                              </div>
                              <div className="text-sm text-gray-500">{prescription.patient_id}</div>
                            </td>
                            <td className="px-6 py-4">
                              <div className="text-sm text-gray-900">{prescription.medication_name}</div>
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                              {prescription.dosage}
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                              {prescription.frequency}
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap">
                              <span className={`px-3 py-1 text-xs font-semibold rounded-full ${
                                prescription.status === 'dispensed' ? 'bg-green-100 text-green-800' :
                                prescription.status === 'active' ? 'bg-yellow-100 text-yellow-800' :
                                'bg-gray-100 text-gray-800'
                              }`}>
                                {prescription.status}
                              </span>
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                              {new Date(prescription.issued_at).toLocaleDateString()}
                            </td>
                          </tr>
                        ))
                      )}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'patientHistory' && (
            <div>
              <div className="bg-white rounded-xl shadow-lg p-6 mb-6">
                <h3 className="text-2xl font-bold text-gray-900 mb-6">Patient Triage History</h3>
                
                {/* Patient Selection */}
                <div className="mb-6">
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Select Patient to View History
                  </label>
                  <select
                    value={selectedPatientHistory?.id || ''}
                    onChange={(e) => {
                      const patient = patients.find(p => p.id === e.target.value);
                      setSelectedPatientHistory(patient);
                      if (patient) {
                        fetchPatientTriageHistory(patient.id);
                      } else {
                        setPatientTriageHistory([]);
                      }
                    }}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  >
                    <option value="">Choose a patient...</option>
                    {patients.map((patient) => (
                      <option key={patient.id} value={patient.id}>
                        {patient.patient_id} - {patient.first_name} {patient.last_name}
                      </option>
                    ))}
                  </select>
                </div>
                
                {/* Triage History Display */}
                {selectedPatientHistory && (
                  <div>
                    {patientTriageHistory.length === 0 ? (
                      <div className="text-center py-12 bg-gray-50 rounded-lg">
                        <span className="text-6xl mb-4 block">🩺</span>
                        <p className="text-gray-600 text-lg">No triage records for this patient</p>
                      </div>
                    ) : (
                      <div className="space-y-6">
                        {patientTriageHistory.map((record) => (
                          <div key={record.id} className="border border-gray-200 rounded-lg p-6 hover:shadow-md transition-shadow bg-gray-50">
                            <div className="flex justify-between items-start mb-4">
                              <div>
                                <h4 className="text-lg font-semibold text-gray-900">
                                  Triage Assessment - {new Date(record.created_at).toLocaleDateString()}
                                </h4>
                                <p className="text-sm text-gray-600">
                                  Performed by {record.nurse_first_name} {record.nurse_last_name}
                                </p>
                                <p className="text-xs text-gray-500 mt-1">
                                  {new Date(record.created_at).toLocaleTimeString()}
                                </p>
                              </div>
                              <span className={`px-4 py-2 rounded-full text-sm font-semibold ${
                                record.triage_category === 'red' ? 'bg-red-100 text-red-800' :
                                record.triage_category === 'orange' ? 'bg-orange-100 text-orange-800' :
                                record.triage_category === 'yellow' ? 'bg-yellow-100 text-yellow-800' :
                                'bg-green-100 text-green-800'
                              }`}>
                                {record.triage_category.toUpperCase()} Priority
                              </span>
                            </div>
                            
                            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-4">
                              <div className="bg-blue-100 rounded-lg p-3">
                                <p className="text-xs text-blue-700 font-semibold mb-1">Blood Pressure</p>
                                <p className="text-lg font-bold text-gray-900">
                                  {record.blood_pressure_systolic}/{record.blood_pressure_diastolic}
                                </p>
                                <p className="text-xs text-gray-600">mmHg</p>
                              </div>
                              
                              <div className="bg-red-100 rounded-lg p-3">
                                <p className="text-xs text-red-700 font-semibold mb-1">Heart Rate</p>
                                <p className="text-lg font-bold text-gray-900">{record.heart_rate}</p>
                                <p className="text-xs text-gray-600">bpm</p>
                              </div>
                              
                              <div className="bg-orange-100 rounded-lg p-3">
                                <p className="text-xs text-orange-700 font-semibold mb-1">Temperature</p>
                                <p className="text-lg font-bold text-gray-900">{record.temperature}</p>
                                <p className="text-xs text-gray-600">°C</p>
                              </div>
                              
                              <div className="bg-purple-100 rounded-lg p-3">
                                <p className="text-xs text-purple-700 font-semibold mb-1">Weight</p>
                                <p className="text-lg font-bold text-gray-900">{record.weight}</p>
                                <p className="text-xs text-gray-600">kg</p>
                              </div>
                            </div>
                            
                            {(record.oxygen_saturation || record.respiratory_rate || record.height || record.bmi) && (
                              <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-4">
                                {record.oxygen_saturation && (
                                  <div className="bg-green-100 rounded-lg p-3">
                                    <p className="text-xs text-green-700 font-semibold mb-1">Oxygen Saturation</p>
                                    <p className="text-lg font-bold text-gray-900">{record.oxygen_saturation}</p>
                                    <p className="text-xs text-gray-600">%</p>
                                  </div>
                                )}
                                
                                {record.respiratory_rate && (
                                  <div className="bg-teal-100 rounded-lg p-3">
                                    <p className="text-xs text-teal-700 font-semibold mb-1">Respiratory Rate</p>
                                    <p className="text-lg font-bold text-gray-900">{record.respiratory_rate}</p>
                                    <p className="text-xs text-gray-600">breaths/min</p>
                                  </div>
                                )}
                                
                                {record.height && (
                                  <div className="bg-indigo-100 rounded-lg p-3">
                                    <p className="text-xs text-indigo-700 font-semibold mb-1">Height</p>
                                    <p className="text-lg font-bold text-gray-900">{record.height}</p>
                                    <p className="text-xs text-gray-600">cm</p>
                                  </div>
                                )}
                                
                                {record.bmi && (
                                  <div className="bg-pink-100 rounded-lg p-3">
                                    <p className="text-xs text-pink-700 font-semibold mb-1">BMI</p>
                                    <p className="text-lg font-bold text-gray-900">{record.bmi}</p>
                                    <p className="text-xs text-gray-600">kg/m²</p>
                                  </div>
                                )}
                              </div>
                            )}
                            
                            {record.chief_complaint && (
                              <div className="bg-white border border-gray-300 rounded-lg p-4 mb-4">
                                <p className="text-xs text-gray-700 font-semibold mb-1">Chief Complaint</p>
                                <p className="text-sm text-gray-900">{record.chief_complaint}</p>
                              </div>
                            )}
                            
                            {record.notes && (
                              <div className="bg-blue-50 border border-blue-300 rounded-lg p-4 mb-4">
                                <p className="text-xs text-blue-700 font-semibold mb-1">Notes</p>
                                <p className="text-sm text-gray-800">{record.notes}</p>
                              </div>
                            )}
                            
                            {record.severity && (
                              <div className="mt-4 flex items-center text-sm">
                                <span className={`px-3 py-1 rounded-full font-semibold ${
                                  record.severity === 'critical' ? 'bg-red-200 text-red-900' :
                                  record.severity === 'urgent' ? 'bg-orange-200 text-orange-900' :
                                  'bg-green-200 text-green-900'
                                }`}>
                                  Severity: {record.severity.toUpperCase()}
                                </span>
                              </div>
                            )}
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                )}
              </div>
            </div>
          )}

          {activeTab === 'portfolio' && (
            <div className="bg-white rounded-xl shadow-lg p-8">
              <h3 className="text-2xl font-bold text-gray-900 mb-6">My Portfolio</h3>
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Name</label>
                  <p className="text-lg text-gray-900">Dr. {user?.firstName} {user?.lastName}</p>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Email</label>
                  <p className="text-lg text-gray-900">{user?.email}</p>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Specialization</label>
                  <p className="text-lg text-gray-900">General Physician</p>
                </div>
              </div>
            </div>
          )}
        </main>
      </div>
      
      {/* Prescription Modal */}
      {showPrescriptionModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl shadow-2xl max-w-2xl w-full p-8 max-h-[90vh] overflow-y-auto">
            <h3 className="text-2xl font-bold text-gray-900 mb-6">Create Prescription</h3>
            
            <form onSubmit={handleCreatePrescription}>
              {/* Patient Selection */}
              <div className="mb-4">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Select Patient *
                </label>
                <select
                  value={selectedPatient?.id || ''}
                  onChange={(e) => {
                    const patient = patients.find(p => p.id === e.target.value);
                    setSelectedPatient(patient);
                  }}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                  required
                >
                  <option value="">Choose a patient...</option>
                  {patients.map((patient) => (
                    <option key={patient.id} value={patient.id}>
                      {patient.patient_id} - {patient.first_name} {patient.last_name}
                    </option>
                  ))}
                </select>
              </div>
              
              {/* Medication Name */}
              <div className="mb-4">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Medication Name *
                </label>
                <input
                  type="text"
                  value={prescriptionForm.medication_name}
                  onChange={(e) => setPrescriptionForm({...prescriptionForm, medication_name: e.target.value})}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                  placeholder="e.g., Paracetamol"
                  required
                />
              </div>
              
              {/* Dosage */}
              <div className="mb-4">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Dosage *
                </label>
                <input
                  type="text"
                  value={prescriptionForm.dosage}
                  onChange={(e) => setPrescriptionForm({...prescriptionForm, dosage: e.target.value})}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                  placeholder="e.g., 500mg"
                  required
                />
              </div>
              
              {/* Frequency */}
              <div className="mb-4">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Frequency *
                </label>
                <input
                  type="text"
                  value={prescriptionForm.frequency}
                  onChange={(e) => setPrescriptionForm({...prescriptionForm, frequency: e.target.value})}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                  placeholder="e.g., 3 times daily"
                  required
                />
              </div>
              
              {/* Duration */}
              <div className="mb-4">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Duration *
                </label>
                <input
                  type="text"
                  value={prescriptionForm.duration}
                  onChange={(e) => setPrescriptionForm({...prescriptionForm, duration: e.target.value})}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                  placeholder="e.g., 5 days"
                  required
                />
              </div>
              
              {/* Instructions */}
              <div className="mb-6">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Instructions
                </label>
                <textarea
                  value={prescriptionForm.instructions}
                  onChange={(e) => setPrescriptionForm({...prescriptionForm, instructions: e.target.value})}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-green-500 focus:border-transparent"
                  rows="3"
                  placeholder="Additional instructions for the patient..."
                />
              </div>
              
              <div className="flex space-x-4">
                <button
                  type="submit"
                  className="flex-1 px-6 py-3 bg-green-500 text-white rounded-lg hover:bg-green-600 transition-colors font-semibold"
                >
                  Create Prescription
                </button>
                <button
                  type="button"
                  onClick={() => {
                    setShowPrescriptionModal(false);
                    setSelectedPatient(null);
                    setPrescriptionForm({
                      medication_name: '',
                      dosage: '',
                      frequency: '',
                      duration: '',
                      instructions: ''
                    });
                  }}
                  className="flex-1 px-6 py-3 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors font-semibold"
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
      
      {/* Lab Test Modal */}
      {showLabTestModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl shadow-2xl max-w-2xl w-full p-8 max-h-[90vh] overflow-y-auto">
            <h3 className="text-2xl font-bold text-gray-900 mb-6">Order Lab Test</h3>
            
            <form onSubmit={handleCreateLabTest}>
              {/* Patient Selection */}
              <div className="mb-4">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Select Patient *
                </label>
                <select
                  value={selectedPatient?.id || ''}
                  onChange={(e) => {
                    const patient = patients.find(p => p.id === e.target.value);
                    setSelectedPatient(patient);
                  }}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  required
                >
                  <option value="">Choose a patient...</option>
                  {patients.map((patient) => (
                    <option key={patient.id} value={patient.id}>
                      {patient.patient_id} - {patient.first_name} {patient.last_name}
                    </option>
                  ))}
                </select>
              </div>
              
              {/* Test Type */}
              <div className="mb-4">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Test Type *
                </label>
                <select
                  value={labTestForm.test_type}
                  onChange={(e) => {
                    setLabTestForm({...labTestForm, test_type: e.target.value, test_name: ''});
                  }}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  required
                >
                  <option value="hematology">Hematology</option>
                  <option value="chemistry">Chemistry</option>
                  <option value="microbiology">Microbiology</option>
                  <option value="immunology">Immunology</option>
                  <option value="urinalysis">Urinalysis</option>
                  <option value="parasitology">Parasitology</option>
                </select>
              </div>
              
              {/* Test Name */}
              <div className="mb-4">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Test Name *
                </label>
                <select
                  value={labTestForm.test_name}
                  onChange={(e) => setLabTestForm({...labTestForm, test_name: e.target.value})}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  required
                >
                  <option value="">Choose a test...</option>
                  {commonLabTests[labTestForm.test_type]?.map((test) => (
                    <option key={test} value={test}>
                      {test}
                    </option>
                  ))}
                </select>
              </div>
              
              {/* Notes */}
              <div className="mb-6">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Notes
                </label>
                <textarea
                  value={labTestForm.notes}
                  onChange={(e) => setLabTestForm({...labTestForm, notes: e.target.value})}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  rows="3"
                  placeholder="Additional notes or special instructions..."
                />
              </div>
              
              <div className="flex space-x-4">
                <button
                  type="submit"
                  className="flex-1 px-6 py-3 bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition-colors font-semibold"
                >
                  Order Lab Test
                </button>
                <button
                  type="button"
                  onClick={() => {
                    setShowLabTestModal(false);
                    setSelectedPatient(null);
                    setLabTestForm({
                      test_type: 'hematology',
                      test_name: '',
                      notes: ''
                    });
                  }}
                  className="flex-1 px-6 py-3 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors font-semibold"
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default DoctorDashboard;
